import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { clearAuth } from '../api';
import { Menu, X, Home, MessageSquare, AlertTriangle, Bell, Users, LogOut } from 'lucide-react';

const navItems = [
  { name: 'Home',      path: '/user/home',      icon: Home },
  { name: 'Feedback',  path: '/user/feedback',  icon: MessageSquare },
  { name: 'Complaint', path: '/user/complaint', icon: AlertTriangle },
  { name: 'Notices',   path: '/user/notices',   icon: Bell },
  { name: 'Societies', path: '/user/societies', icon: Users },
];

const Navbar = () => {
  const location  = useLocation();
  const navigate  = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = () => {
    clearAuth();
    navigate('/login');
  };

return (
  <>
    <nav className="sticky top-0 z-50 flex items-center justify-between px-6 md:px-12 h-[72px]
      bg-slate-950/70 backdrop-blur-2xl border-b border-white/10">

      {/* Logo */}
      <div
        onClick={() => navigate('/user/home')}
        className="flex items-center gap-2 cursor-pointer group"
      >
        <span className="text-2xl text-yellow-400 group-hover:rotate-12 transition-transform duration-300">
          ⬡
        </span>
        <span className="text-lg font-semibold tracking-wide text-yellow-400
          group-hover:text-yellow-300 transition-all">
          HostelMate
        </span>
      </div>

      {/* Desktop Nav */}
      <div className="hidden md:flex items-center gap-2 relative">

        {navItems.map(({ name, path, icon: Icon }) => {
          const active = location.pathname === path;

          return (
            <Link
              key={path}
              to={path}
              className={`relative flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium
              transition-all duration-300 group
              ${active
                ? 'text-yellow-400'
                : 'text-gray-400 hover:text-white'
              }`}
            >
              <Icon size={16} />

              {name}

              {/* Active Glow */}
              {active && (
                <span className="absolute inset-0 rounded-lg bg-yellow-400/10 blur-md -z-10"></span>
              )}

              {/* Bottom Indicator */}
              <span className={`absolute bottom-0 left-1/2 h-[2px] bg-yellow-400 transition-all duration-300
                ${active ? 'w-3/4 -translate-x-1/2' : 'w-0 group-hover:w-1/2 group-hover:-translate-x-1/2'}`}>
              </span>
            </Link>
          );
        })}

        {/* Logout */}
        <button
          onClick={handleLogout}
          className="ml-3 px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2
          text-red-400 bg-red-500/10 border border-red-500/20
          hover:bg-red-500/20 hover:scale-[1.03]
          transition-all duration-300 shadow-sm hover:shadow-lg"
        >
          <LogOut size={16} />
          Logout
        </button>
      </div>

      {/* Hamburger */}
      <div
        className="md:hidden text-yellow-400 cursor-pointer transition-transform hover:scale-110"
        onClick={() => setMenuOpen(!menuOpen)}
      >
        {menuOpen ? <X size={26} /> : <Menu size={26} />}
      </div>
    </nav>

    {/* Mobile Menu */}
    <div
      className={`md:hidden overflow-hidden transition-all duration-300
      ${menuOpen ? 'max-h-[500px] opacity-100' : 'max-h-0 opacity-0'}`}
    >
      <div className="flex flex-col px-6 py-4 gap-2 bg-slate-950/95 backdrop-blur-xl border-b border-white/10">

        {navItems.map(({ name, path, icon: Icon }) => {
          const active = location.pathname === path;

          return (
            <Link
              key={path}
              to={path}
              onClick={() => setMenuOpen(false)}
              className={`flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium
              transition-all duration-300
              ${active
                ? 'bg-yellow-400/10 text-yellow-400 border border-yellow-400/20'
                : 'text-gray-400 hover:text-white hover:bg-white/5'
              }`}
            >
              <Icon size={18} />
              {name}
            </Link>
          );
        })}

        <button
          onClick={() => { handleLogout(); setMenuOpen(false); }}
          className="flex items-center gap-3 px-4 py-3 mt-2 rounded-lg text-sm font-medium
          text-red-400 bg-red-500/10 border border-red-500/20
          hover:bg-red-500/20 transition-all duration-300"
        >
          <LogOut size={18} />
          Logout
        </button>
      </div>
    </div>
  </>
);
};

export default Navbar;
